        "hooks.slack.com",
        "api.stripe.com",
        "api.twilio.com",
        "graph.facebook.com",
        "api.sendgrid.com"
    };

    public static bool IsAllowedUrl(string url)
    {
        if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            return false;

        if (uri.Scheme != "https")
            return false;

        if (!AllowedHosts.Contains(uri.Host))
            return false;

        return true;
    }
}

